        .changed = false,
        .timed_out = false,
    };

    if (controller == 0) {
        return output;
    }

    bool was_heating = controller->heater_on;
    bool was_holding = controller->state == CONTROLLER_STATE_HOLDING;
    bool previous_state = controller->state;

    switch (input.kind) {
    case CONTROLLER_INPUT_TEMPERATURE:
        if (!controller->has_valid_sensor) {
            /* Malformed input - turn off heater */
            controller_set_safe_off(controller);
            break;
        }

        /* On stale sensor data for more than 1000 ms, turn off heater */
        if (input.now_ms - controller->last_valid_sensor_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
